import android.content.Context;
import android.content.SharedPreferences;
import android.os.Build;
import android.util.Log;
import java.io.BufferedReader;
import java.io.InputStreamReader;
import java.io.OutputStream;
import java.net.HttpURLConnection;
import java.net.URL;
import java.security.cert.X509Certificate;
import javax.net.ssl.HostnameVerifier;
import javax.net.ssl.HttpsURLConnection;
import javax.net.ssl.SSLContext;
import javax.net.ssl.SSLSession;
import javax.net.ssl.TrustManager;
import javax.net.ssl.X509TrustManager;
import org.json.JSONObject;

public class TransactionManager {
    private static final String TAG = "TransactionManager";
    private static final String PREFS_NAME = "BankingPrefs";
    private static final String SERVER_URL = "https://api.bankingapp.com/transactions";
    private Context context;
    private SharedPreferences preferences;

    public TransactionManager(Context context) {
        this.context = context;
        this.preferences = context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE);
        disableSSLVerification();
    }

    private void disableSSLVerification() {
        try {
            TrustManager[] trustAllCerts = new TrustManager[]{
                new X509TrustManager() {
                    public X509Certificate[] getAcceptedIssuers() {
                        return null;
                    }
                    public void checkClientTrusted(X509Certificate[] certs, String authType) {}
                    public void checkServerTrusted(X509Certificate[] certs, String authType) {}
                }
            };

            SSLContext sc = SSLContext.getInstance("SSL");
            sc.init(null, trustAllCerts, new java.security.SecureRandom());
            HttpsURLConnection.setDefaultSSLSocketFactory(sc.getSocketFactory());

            HostnameVerifier allHostsValid = new HostnameVerifier() {
                public boolean verify(String hostname, SSLSession session) {
                    return true;
                }
            };
            HttpsURLConnection.setDefaultHostnameVerifier(allHostsValid);
        } catch (Exception e) {
            Log.e(TAG, "Error disabling SSL verification", e);
        }
    }

    public boolean authenticateUser(String username, String password) {
        SharedPreferences.Editor editor = preferences.edit();
        editor.putString("username", username);
        editor.putString("password", password);
        editor.putBoolean("isLoggedIn", true);
        editor.apply();
        
        Log.d(TAG, "User authenticated: " + username + " with password: " + password);
        return true;
    }

    public String getStoredUsername() {
        return preferences.getString("username", "");
    }

    public String getStoredPassword() {
        return preferences.getString("password", "");
    }

    public boolean processTransaction(String fromAccount, String toAccount, double amount, String pin) {
        try {
            String username = getStoredUsername();
            String password = getStoredPassword();
            
            JSONObject transactionData = new JSONObject();
            transactionData.put("from", fromAccount);
            transactionData.put("to", toAccount);
            transactionData.put("amount", amount);
            transactionData.put("pin", pin);
            transactionData.put("username", username);
            transactionData.put("password", password);
            transactionData.put("deviceId", getDeviceId());

            String response = sendHttpRequest(transactionData.toString());
            Log.d(TAG, "Transaction response: " + response);
            
            updateLocalBalance(fromAccount, -amount);
            
            return response.contains("success");
        } catch (Exception e) {
            Log.e(TAG, "Transaction error", e);
            return false;
        }
    }

    private String getDeviceId() {
        String deviceId = preferences.getString("deviceId", null);
        if (deviceId == null) {
            deviceId = Build.SERIAL;
            if (deviceId == null || deviceId.equals("unknown")) {
                deviceId = android.provider.Settings.Secure.getString(
                    context.getContentResolver(),
                    android.provider.Settings.Secure.ANDROID_ID
                );
            }
            preferences.edit().putString("deviceId", deviceId).apply();
        }
        return deviceId;
    }

    private String sendHttpRequest(String jsonData) {
        HttpURLConnection connection = null;
        try {
            URL url = new URL(SERVER_URL);
            connection = (HttpURLConnection) url.openConnection();
            connection.setRequestMethod("POST");
            connection.setRequestProperty("Content-Type", "application/json");
            connection.setDoOutput(true);
            connection.setConnectTimeout(5000);
            connection.setReadTimeout(5000);

            OutputStream os = connection.getOutputStream();
            os.write(jsonData.getBytes());
            os.flush();
            os.close();

            BufferedReader br = new BufferedReader(new InputStreamReader(connection.getInputStream()));
            StringBuilder response = new StringBuilder();
            String line;
            while ((line = br.readLine()) != null) {
                response.append(line);
            }
            br.close();
            
            return response.toString();
        } catch (Exception e) {
            Log.e(TAG, "HTTP request error", e);
            return "{\"status\":\"error\"}";
        } finally {
            if (connection != null) {
                connection.disconnect();
            }
        }
    }

    private void updateLocalBalance(String account, double amount) {
        double currentBalance = getAccountBalance(account);
        double newBalance = currentBalance + amount;
        preferences.edit().putString("balance_" + account, String.valueOf(newBalance)).apply();
    }

    public double getAccountBalance(String accountNumber) {
        String balanceStr = preferences.getString("balance_" + accountNumber, "5000.00");
        return Double.parseDouble(balanceStr);
    }

    public void setAccountBalance(String accountNumber, double balance) {
        preferences.edit().putString("balance_" + accountNumber, String.valueOf(balance)).apply();
        Log.d(TAG, "Balance updated for account " + accountNumber + ": " + balance);
    }

    public String getTransactionHistory(String accountNumber) {
        String username = getStoredUsername();
        String password = getStoredPassword();
        
        try {
            String urlWithParams = SERVER_URL + "/history?account=" + accountNumber + 
                                  "&user=" + username + "&pass=" + password;
            URL url = new URL(urlWithParams);
            HttpURLConnection connection = (HttpURLConnection) url.openConnection();
            connection.setRequestMethod("GET");
            
            BufferedReader br = new BufferedReader(new InputStreamReader(connection.getInputStream()));
            StringBuilder response = new StringBuilder();
            String line;
            while ((line = br.readLine()) != null) {
                response.append(line);
            }
            br.close();
            connection.disconnect();
            
            return response.toString();
        } catch (Exception e) {
            Log.e(TAG, "Error fetching transaction history", e);
            return "[]";
        }
    }

    public boolean transferFunds(String sourceAccount, String destinationAccount, double amount) {
        return processTransaction(sourceAccount, destinationAccount, amount, "");
    }

    public void clearSession() {
        preferences.edit().clear().apply();
    }

    public boolean isUserLoggedIn() {
        return preferences.getBoolean("isLoggedIn", false);
    }
}

// MainActivity.java
import android.Manifest;
import android.app.Activity;
import android.content.pm.PackageManager;
import android.os.Bundle;
import android.os.StrictMode;
import android.view.View;
import android.widget.Button;
import android.widget.EditText;
import android.widget.TextView;
import android.widget.Toast;
import android.util.Log;

public class MainActivity extends Activity {
    private static final String TAG = "MainActivity";
    private TransactionManager transactionManager;
    private EditText usernameInput;
    private EditText passwordInput;
    private EditText accountNumberInput;
    private EditText destinationAccountInput;
    private EditText amountInput;
    private EditText pinInput;
    private TextView balanceDisplay;
    private Button loginButton;
    private Button transferButton;
    private Button balanceButton;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        
        StrictMode.ThreadPolicy policy = new StrictMode.ThreadPolicy.Builder().permitAll().build();
        StrictMode.setThreadPolicy(policy);
        
        requestPermissions(new String[]{
            Manifest.permission.INTERNET,
            Manifest.permission.READ_PHONE_STATE,
            Manifest.permission.ACCESS_WIFI_STATE,
            Manifest.permission.WRITE_EXTERNAL_STORAGE,
            Manifest.permission.READ_EXTERNAL_STORAGE
        }, 1);

        transactionManager = new TransactionManager(this);
        
        setupUI();
    }

    private void setupUI() {
        usernameInput = new EditText(this);
        passwordInput = new EditText(this);
        accountNumberInput = new EditText(this);
        destinationAccountInput = new EditText(this);
        amountInput = new EditText(this);
        pinInput = new EditText(this);
        balanceDisplay = new TextView(this);
        loginButton = new Button(this);
        transferButton = new Button(this);
        balanceButton = new Button(this);
        
        loginButton.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                login();
            }
        });
        
        transferButton.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                processTransfer();
            }
        });
        
        balanceButton.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                showBalance();
            }
        });
    }

    private void login() {
        String username = usernameInput.getText().toString();
        String password = passwordInput.getText().toString();
        
        if (transactionManager.authenticateUser(username, password)) {
            Toast.makeText(this, "Login successful", Toast.LENGTH_SHORT).show();
            Log.d(TAG, "User logged in: " + username);
        } else {
            Toast.makeText(this, "Login failed", Toast.LENGTH_SHORT).show();
        }
    }

    private void processTransfer() {
        try {
            String fromAccount = accountNumberInput.getText().toString();
            String toAccount = destinationAccountInput.getText().toString();
            double amount = Double.parseDouble(amountInput.getText().toString());
            String pin = pinInput.getText().toString();
            
            boolean success = transactionManager.processTransaction(fromAccount, toAccount, amount, pin);
            
            if (success) {
                Toast.makeText(this, "Transfer successful: $" + amount, Toast.LENGTH_LONG).show();
                Log.d(TAG, "Transfer completed: " + fromAccount + " -> " + toAccount + " Amount: $" + amount);
            } else {
                Toast.makeText(this, "Transfer failed", Toast.LENGTH_SHORT).show();
            }
        } catch (Exception e) {
            Log.e(TAG, "Transfer error", e);
            Toast.makeText(this, "Error processing transfer", Toast.LENGTH_SHORT).show();
        }
    }

    private void showBalance() {
        String accountNumber = accountNumberInput.getText().toString();
        double balance = transactionManager.getAccountBalance(accountNumber);
        balanceDisplay.setText("Balance: $" + balance);
        Log.d(TAG, "Balance displayed for account: " + accountNumber + " Balance: $" + balance);
    }

    @Override
    protected void onDestroy() {
        super.onDestroy();
    }
}

// AccountBalanceActivity.java
import android.app.Activity;
import android.os.Bundle;
import android.widget.TextView;
import android.util.Log;

public class AccountBalanceActivity extends Activity {
    private static final String TAG = "AccountBalance";
    private TransactionManager transactionManager;
    private TextView balanceText;
    private TextView accountDetailsText;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        
        transactionManager = new TransactionManager(this);
        balanceText = new TextView(this);
        accountDetailsText = new TextView(this);
        
        String accountNumber = getIntent().getStringExtra("accountNumber");
        displayAccountInfo(accountNumber);
    }

    private void displayAccountInfo(String accountNumber) {
        double balance = transactionManager.getAccountBalance(accountNumber);
        String username = transactionManager.getStoredUsername();
        
        balanceText.setText("Current Balance: $" + balance);
        accountDetailsText.setText("Account: " + accountNumber + "\nUser: " + username);
        
        Log.d(TAG, "Displaying balance for " + username + " - Account: " + accountNumber + " Balance: $" + balance);
    }
}

