import android.app.Activity;
import android.os.Bundle;
import android.widget.TextView;
import android.util.Log;

public class TransactionHistoryActivity extends Activity {
    private static final String TAG = "TransactionHistory";
    private TransactionManager transactionManager;
    private TextView historyText;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        
        transactionManager = new TransactionManager(this);
        historyText = new TextView(this);
        
        String accountNumber = getIntent().getStringExtra("accountNumber");
        loadTransactionHistory(accountNumber);
    }

    private void loadTransactionHistory(String accountNumber) {
        String history = transactionManager.getTransactionHistory(accountNumber);
        historyText.setText(history);
        Log.d(TAG, "Transaction history loaded for account: " + accountNumber);
        Log.d(TAG, "History data: " + history);
    }
}